import React from 'react';
import { Link } from 'react-router-dom';

const NotFound = () => {
  const styles = {
    wrapper: {
      height: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(to right, #f9f9f9, #e0e0e0)',
      textAlign: 'center',
      padding: '20px',
    },
    content: {
      maxWidth: '500px',
      padding: '40px',
      background: 'white',
      borderRadius: '12px',
      boxShadow: '0 0 15px rgba(0, 0, 0, 0.1)',
    },
    h1: {
      fontSize: '6rem',
      color: '#d32f2f',
      marginBottom: '10px',
    },
    h2: {
      fontSize: '2rem',
      color: '#444',
      marginBottom: '10px',
    },
    p: {
      fontSize: '1.1rem',
      color: '#666',
      marginBottom: '25px',
    },
    link: {
      display: 'inline-block',
      backgroundColor: '#2e7d32',
      color: '#fff',
      padding: '12px 24px',
      borderRadius: '6px',
      textDecoration: 'none',
      fontWeight: 'bold',
      transition: 'background-color 0.3s ease',
    },
    linkHover: {
      backgroundColor: '#1b5e20',
    }
  };

  return (
    <div style={styles.wrapper}>
      <div style={styles.content}>
        <h1 style={styles.h1}>404</h1>
        <h2 style={styles.h2}>Page Not Found</h2>
        <p style={styles.p}>Sorry, the page you are looking for does not exist.</p>
        <Link
          to="/"
          style={styles.link}
          onMouseOver={e => (e.target.style.backgroundColor = styles.linkHover.backgroundColor)}
          onMouseOut={e => (e.target.style.backgroundColor = styles.link.backgroundColor)}
        >
          Go Back Home
        </Link>
      </div>
    </div>
  );
};

export default NotFound;
